// src/utils/localStorage.js
const STORAGE_KEY = 'cascade_project_briefs';

export const getProjectBriefs = () => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return [];
        return JSON.parse(data);
    } catch (error) {
        console.error('Error reading from localStorage:', error);
        return [];
    }
};

export const saveProjectBriefs = (briefs) => {
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(briefs));
        return true;
    } catch (error) {
        console.error('Error saving to localStorage:', error);
        return false;
    }
};

export const updateProjectBrief = (index, updatedData) => {
    const briefs = getProjectBriefs();
    if (index >= 0 && index < briefs.length) {
        briefs[index] = { ...briefs[index], ...updatedData };
        return saveProjectBriefs(briefs);
    }
    return false;
};

export const deleteProjectBrief = (index) => {
    const briefs = getProjectBriefs();
    if (index >= 0 && index < briefs.length) {
        briefs.splice(index, 1);
        return saveProjectBriefs(briefs);
    }
    return false;
};

export const getProjectStats = () => {
    const briefs = getProjectBriefs();
    const total = briefs.length;
    
    // Count by project type
    const byType = briefs.reduce((acc, brief) => {
        const type = brief.projectType || 'other';
        acc[type] = (acc[type] || 0) + 1;
        return acc;
    }, {});

    // Count by status
    const byStatus = briefs.reduce((acc, brief) => {
        const status = brief.status || 'new';
        acc[status] = (acc[status] || 0) + 1;
        return acc;
    }, {});

    // Count by deposit paid
    const depositPaid = briefs.filter(b => b.depositPaid === true).length;
    const depositPending = briefs.filter(b => b.depositPaid !== true).length;

    // Recent submissions (last 7 days)
    const weekAgo = new Date();
    weekAgo.setDate(weekAgo.getDate() - 7);
    const recent = briefs.filter(b => new Date(b.submittedAt) > weekAgo).length;

    // Projects that are in progress (started but not completed)
    const inProgress = briefs.filter(b => b.status === 'in-progress' || b.status === 'reviewing' || b.status === 'deposit-paid').length;

    // Projects with estimated completion dates
    const withEstimates = briefs.filter(b => b.estimatedCompletion).length;

    return { total, byType, byStatus, byDeposit: { paid: depositPaid, pending: depositPending }, recent, inProgress, withEstimates };
};

export const formatProjectType = (type) => {
    const types = {
        'full-build': 'Full Build',
        'revamp': 'Revamp / Redesign',
        'landing-page': 'Landing Page',
        'ecommerce': 'E-commerce Store',
        'dashboard': 'Dashboard / Analytics',
        'custom-system': 'Custom Business System',
        'other': 'Other'
    };
    return types[type] || type || 'Not specified';
};

export const formatBudget = (budget) => {
    const budgets = {
        'under-5k': 'Under R5,000',
        '5k-15k': 'R5,000 – R15,000',
        '15k-30k': 'R15,000 – R30,000',
        '30k-50k': 'R30,000 – R50,000',
        '50k-100k': 'R50,000 – R100,000',
        '100k+': 'R100,000+'
    };
    return budgets[budget] || budget || 'Not specified';
};

export const formatTimeline = (timeline) => {
    const timelines = {
        'urgent': 'Urgent (Within 2 weeks)',
        '1-month': '1 Month',
        '2-3-months': '2 – 3 Months',
        '3-6-months': '3 – 6 Months',
        'flexible': 'Flexible'
    };
    return timelines[timeline] || timeline || 'Not specified';
};

export const formatStatus = (status) => {
    const statuses = {
        'new': 'New',
        'reviewing': 'Reviewing',
        'contacted': 'Contacted',
        'proposal-sent': 'Proposal Sent',
        'deposit-paid': 'Deposit Paid',
        'in-progress': 'In Progress',
        'completed': 'Completed',
        'archived': 'Archived'
    };
    return statuses[status] || status || 'New';
};

export const getStatusColor = (status) => {
    const colors = {
        'new': '#0066cc',
        'reviewing': '#d4a000',
        'contacted': '#009688',
        'proposal-sent': '#5e3c9e',
        'deposit-paid': '#0d7c3f',
        'in-progress': '#0d7c3f',
        'completed': '#0d7c3f',
        'archived': '#64748b'
    };
    return colors[status] || '#64748b';
};