import React from 'react';
import { formatProjectType, formatStatus, getStatusColor, formatBudget, formatTimeline } from '../utils/localStorage';
import './ProjectCard.css';

function ProjectCard({ project, index, onSelect }) {
  const statusColor = getStatusColor(project.status || 'new');
  const statusLabel = formatStatus(project.status || 'new');
  const projectType = formatProjectType(project.projectType);
  const submittedDate = new Date(project.submittedAt);
  const timeAgo = getTimeAgo(submittedDate);

  function getTimeAgo(date) {
    const diff = Date.now() - date.getTime();
    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);

    if (minutes < 1) return 'Just now';
    if (minutes < 60) return `${minutes}m ago`;
    if (hours < 24) return `${hours}h ago`;
    if (days < 7) return `${days}d ago`;
    return date.toLocaleDateString();
  }

  const handleClick = () => {
    onSelect(project, index);
  };

  return (
    <tr className="project-row" onClick={handleClick} title={project.description || ''}>
      <td className="cell-project" style={{ borderLeftColor: statusColor }}>
        <div className="cell-project-name">{project.projectName || 'Untitled Project'}</div>
        <div className="cell-project-type">{projectType}</div>
      </td>
      <td className="cell-client">
        <span className="client-name">{project.name || 'Anonymous'}</span>
        <span className="client-email">{project.email}</span>
      </td>
      <td className="cell-budget">{project.budget ? formatBudget(project.budget) : '—'}</td>
      <td className="cell-timeline">{project.timeline ? formatTimeline(project.timeline) : '—'}</td>
      <td className="cell-status">
        <span className="status-dot" style={{ background: statusColor }} />
        <span className="status-label" style={{ color: statusColor }}>{statusLabel}</span>
      </td>
      <td className="cell-time">{timeAgo}</td>
    </tr>
  );
}

export default ProjectCard;