import React from 'react';
import { formatProjectType, formatStatus } from '../utils/localStorage';
import './SearchFilter.css';

function SearchFilter({ 
  searchTerm, 
  setSearchTerm, 
  filterType, 
  setFilterType,
  filterStatus,
  setFilterStatus
}) {
  const projectTypes = [
    { value: 'all', label: 'All Types' },
    { value: 'full-build', label: 'Full Build' },
    { value: 'revamp', label: 'Revamp' },
    { value: 'landing-page', label: 'Landing Page' },
    { value: 'ecommerce', label: 'E-commerce' },
    { value: 'dashboard', label: 'Dashboard' },
    { value: 'custom-system', label: 'Custom System' },
    { value: 'other', label: 'Other' }
  ];

  const statuses = [
    { value: 'all', label: 'All Status' },
    { value: 'new', label: 'New' },
    { value: 'reviewing', label: 'Reviewing' },
    { value: 'contacted', label: 'Contacted' },
    { value: 'proposal-sent', label: 'Proposal Sent' },
    { value: 'in-progress', label: 'In Progress' },
    { value: 'completed', label: 'Completed' },
    { value: 'archived', label: 'Archived' }
  ];

  return (
    <div className="search-filter">
      <div className="search-bar">
        <span className="search-icon">⌕</span>
        <input
          type="text"
          placeholder="Search name, email, project, description…"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="search-input"
        />
        {searchTerm && (
          <button className="clear-search" onClick={() => setSearchTerm('')}>
            ✕
          </button>
        )}
      </div>

      <div className="filter-controls">
        <div className="filter-group">
          <label>Project Type</label>
          <select 
            value={filterType} 
            onChange={(e) => setFilterType(e.target.value)}
            className="filter-select"
          >
            {projectTypes.map(type => (
              <option key={type.value} value={type.value}>
                {type.label}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-group">
          <label>Status</label>
          <select 
            value={filterStatus} 
            onChange={(e) => setFilterStatus(e.target.value)}
            className="filter-select"
          >
            {statuses.map(status => (
              <option key={status.value} value={status.value}>
                {status.label}
              </option>
            ))}
          </select>
        </div>

        <button 
          className="clear-filters"
          onClick={() => {
            setFilterType('all');
            setFilterStatus('all');
          }}
        >
          Clear Filters
        </button>
      </div>
    </div>
  );
}

export default SearchFilter;