// src/components/StatsCards.js
import React from 'react';
import './StatsCards.css';

function StatsCards({ stats }) {
    const { total, byType, byStatus, byDeposit, recent, inProgress, withEstimates } = stats;

    const statusLabels = {
        'new': 'New',
        'reviewing': 'Reviewing',
        'contacted': 'Contacted',
        'proposal-sent': 'Proposal Sent',
        'deposit-paid': 'Deposit Paid',
        'in-progress': 'In Progress',
        'completed': 'Completed',
        'archived': 'Archived'
    };

    const statusColors = {
        'new': '#3b82f6',
        'reviewing': '#f5a623',
        'contacted': '#14b8a6',
        'proposal-sent': '#8b5cf6',
        'deposit-paid': '#22c55e',
        'in-progress': '#22c55e',
        'completed': '#22c55e',
        'archived': '#647089'
    };

    // Get top 3 project types
    const topTypes = Object.entries(byType)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 3);

    return (
        <div className="stats-cards">
            {/* Total Projects */}
            <div className="stat-card">
                <div className="stat-value">{total}</div>
                <div className="stat-label">Total Projects</div>
                <div className="stat-change">
                    <span className="stat-badge">{recent} new / 7d</span>
                    {inProgress > 0 && (
                        <span className="stat-badge stat-badge-progress">
                            {inProgress} in progress
                        </span>
                    )}
                </div>
            </div>

            {/* Deposit Status */}
            <div className="stat-card">
                <div className="stat-label">Deposit Status</div>
                <div className="deposit-stats">
                    <div className="deposit-item">
                        <span className="deposit-value">{byDeposit?.paid || 0}</span>
                        <span className="deposit-label">Paid</span>
                    </div>
                    <div className="deposit-item">
                        <span className="deposit-value">{byDeposit?.pending || 0}</span>
                        <span className="deposit-label">Pending</span>
                    </div>
                </div>
                <div className="deposit-bar">
                    <div 
                        className="deposit-bar-fill paid" 
                        style={{ 
                            width: total > 0 ? ((byDeposit?.paid || 0) / total * 100) + '%' : '0%' 
                        }}
                    />
                    <div 
                        className="deposit-bar-fill pending" 
                        style={{ 
                            width: total > 0 ? ((byDeposit?.pending || 0) / total * 100) + '%' : '0%' 
                        }}
                    />
                </div>
            </div>

            {/* Status Distribution */}
            <div className="stat-card">
                <div className="stat-label">By Status</div>
                <div className="status-bars">
                    {Object.entries(byStatus).map(([status, count]) => (
                        <div key={status} className="status-bar-item">
                            <span className="status-bar-label">{statusLabels[status] || status}</span>
                            <div className="status-bar-track">
                                <div 
                                    className="status-bar-fill" 
                                    style={{ 
                                        width: `${total > 0 ? (count / total) * 100 : 0}%`,
                                        background: statusColors[status] || '#647089'
                                    }}
                                />
                            </div>
                            <span className="status-bar-count">{count}</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Top Project Types */}
            <div className="stat-card">
                <div className="stat-label">Top Project Types</div>
                {topTypes.length > 0 ? (
                    <div className="type-list">
                        {topTypes.map(([type, count]) => (
                            <div key={type} className="type-item">
                                <span className="type-name">{type.replace('-', ' ')}</span>
                                <span className="type-count">{count}</span>
                            </div>
                        ))}
                        {Object.keys(byType).length > 3 && (
                            <div className="type-item type-more">
                                <span className="type-name">+{Object.keys(byType).length - 3} more</span>
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="empty-state">No projects yet</div>
                )}
            </div>
        </div>
    );
}

export default StatsCards;